@startuml
!theme plain

class "StaticFactory" as StaticFactory {
  <<C>>
  +produce() : produce
}

class "ConcreteProduct1" as ConcreteProduct1 {
  <<C>>
  +produce() : void
}

class "ConcreteProduct2" as ConcreteProduct2 {
  <<C>>
  +produce() : void
}

class "Product" as Product {
  <<A>>
  +void produce()
}

StaticFactory ..> ConcreteProduct1
StaticFactory ..> ConcreteProduct2
ConcreteProduct1 --|> Product
ConcreteProduct2 --|> Product

@enduml
